/**
 * Check if a user-selected ingredient matches a recipe ingredient
 * Handles both German and English ingredient names
 */
function ingredientMatches(userSelected, recipeIngredient) {
  if (!userSelected || !recipeIngredient) return false;
  
  const userNorm = userSelected.toLowerCase().trim();
  const recipeNorm = recipeIngredient.toLowerCase().trim();
  const translations = (typeof ingredientTranslations !== 'undefined')
    ? ingredientTranslations
    : null;
  
  // Direct match (both German or both English)
  if (userNorm === recipeNorm) return true;
  
  // Check if user selected an English name but recipe has German
  if (translations) {
    const germanEquivalent = Object.keys(translations).find(
      de => translations[de] && translations[de].toLowerCase() === userNorm
    );
    if (germanEquivalent && germanEquivalent === recipeNorm) return true;
  }
  
  // Check if user selected a German name and recipe has corresponding English
  if (translations) {
    const englishName = translations[userNorm];
    if (englishName && englishName.toLowerCase() === recipeNorm) return true;
  }
  
  // Partial match fallback (e.g., "paprika" matches "rote paprika")
  if (userNorm && recipeNorm && (recipeNorm.includes(userNorm) || userNorm.includes(recipeNorm))) {
    return true;
  }
  
  return false;
}
